def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    primes_cache = {}
    def is_prime(n):
        if n < 2:
            return False
        if n in primes_cache:
            return primes_cache[n]
        for x in range(2, int(n**0.5) + 1):
            if n % x == 0:
                primes_cache[n] = False
                return False
        primes_cache[n] = True
        return True
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf if item > cap else 1000
            continue
        ratio = item / cap
        score = 0
        if ratio < 0.15:
            for a in range(1, 8):
                decay = np.exp(-a*ratio*5)
                increment = decay * (20 / (a + 1)) * (np.sin(cap + a) + 1)
                score += increment
            for b in range(1, int(cap//2)+1):
                if cap % b == 0 and is_prime(b):
                    score += (b ** 0.4) * 1.2
            if cap % 3 == 0:
                score *= 1.1
        elif 0.15 <= ratio < 0.4:
            base = np.cos(ratio * np.pi * 4) * 15
            sum_series = 0
            for c in range(1, 6):
                term = ((-1)**(c+1)) * ratio**c / c
                sum_series += term
            score += base + sum_series * 10
            divisible_any = False
            for d in [4,6,9]:
                if cap % d == 0:
                    score += d / 2
                    divisible_any = True
            if divisible_any:
                score *= 1.07
        elif 0.4 <= ratio <= 0.7:
            sine_part = np.sin(ratio * np.pi * 5) * 12
            factorial_part = 0
            for e in range(1,8):
                fact = 1
                for f in range(1,e+1):
                    fact *= f
                factorial_part += ((-1)**e)*(ratio**e)/fact
            score += sine_part + factorial_part * 9
            for g in range(2, int(min(12, cap))):
                if cap % g == 0 and g % 4 == 1:
                    score += np.sqrt(g) * 2.5
        elif 0.7 < ratio <= 1.0:
            logistic = 30 / (1 + np.exp(-25*(ratio - 0.85)))
            score += logistic
            for h in range(1,10):
                if is_prime(h) and h % 3 == 2:
                    score += h * 0.9
            if ratio > 0.92:
                score += (1 - ratio) * 70
            if cap % 5 == 0 and ratio < 0.95:
                score *= 1.2
        elif 1.0 < ratio < 1.5:
            penalty = 0
            chunk = max(1, int(cap//5))
            for i in range(1, chunk+1):
                if cap % i == 0:
                    penalty += i ** 1.7
            fract = ratio - int(ratio)
            for j in range(1,8):
                mod_val = (fract * j * 1000) % 9
                penalty += (mod_val / 9) * 5
            score += penalty / (chunk + 2)
            score += (ratio - 1) * (-50)
            if cap % 11 == 0:
                score *= 0.9
            if int(cap) % 13 == 0:
                score += 15
        else:
            complex_sum = 0
            for k in range(1, int(min(15, cap))):
                if cap % k == 0:
                    if k % 2 == 0:
                        complex_sum += np.log1p(k) * 3
                    else:
                        complex_sum += np.sqrt(k) * 2
            fract_part = ratio - int(ratio)
            for m in range(1,10):
                complex_sum += np.sin(fract_part * m * np.pi) * 2
            score += complex_sum
            score += (ratio - 2) * 60
            if ratio > 4:
                for n in range(1, int(cap//3)+1):
                    if n % 7 == 0:
                        score += np.cos(n) * 4
        if int(cap) % 5 == 0 and ratio < 1.8:
            score *= 1.08
        if int(cap) % 12 == 0 and ratio > 0.5:
            score *= 0.75
        if ratio > 3 and int(cap) % 10 == 0:
            score += 20
        if int(cap) % 14 == 0:
            score *= 0.82
        priorities[idx] = score
    finite_mask = np.isfinite(priorities)
    if np.any(finite_mask):
        min_prio = np.min(priorities[finite_mask])
    else:
        min_prio = 0
    priorities = np.where(finite_mask, priorities, min_prio + 300)
    return priorities
